import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json',
    'ngrok-skip-browser-warning': 'true',
  },
});

// Add token to requests if it exists
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const authAPI = {
  signup: (email, password, inviteCode) =>
    api.post('/auth/signup', { email, password, inviteCode }),
  login: (email, password) =>
    api.post('/auth/login', { email, password }),
  getCurrentUser: () =>
    api.get('/auth/me'),
  updateUsername: (username) =>
    api.put('/auth/username', { username }),
};

export const entriesAPI = {
  getAll: (searchTerm) =>
    api.get('/entries', { params: { search: searchTerm } }),
  getById: (id) =>
    api.get(`/entries/${id}`),
  getByWord: (word) =>
    api.get(`/entries/word/${word}`),
  create: (word, partOfSpeech, pronunciation, definition, example, relatedWords, categories) =>
    api.post('/entries', { word, partOfSpeech, pronunciation, definition, example, relatedWords, categories }),
  update: (id, word, partOfSpeech, pronunciation, definition, example, relatedWords, categories, changeDescription) =>
    api.put(`/entries/${id}`, { word, partOfSpeech, pronunciation, definition, example, relatedWords, categories, changeDescription }),
  delete: (id) =>
    api.delete(`/entries/${id}`),
  getPendingSubmissions: () =>
    api.get('/entries/pending/mine'),
  getHistory: (id) =>
    api.get(`/entries/${id}/history`),
  revertToHistory: (id, historyId) =>
    api.post(`/entries/${id}/revert/${historyId}`),
  recordView: (id) =>
    api.post(`/entries/${id}/view`),
  getTopViewed: (limit = 10) =>
    api.get('/entries/stats/top-viewed', { params: { limit } }),
  getAllViewed: () =>
    api.get('/entries/stats/all-viewed'),
};

export const inviteAPI = {
  create: () =>
    api.post('/invite/create'),
  getCodes: () =>
    api.get('/invite/codes'),
  getUsers: () =>
    api.get('/invite/users'),
  updateUserContributor: (userId, isContributor) =>
    api.put(`/invite/users/${userId}/contributor`, { is_contributor: isContributor }),
};

export const adminAPI = {
  getStats: () =>
    api.get('/admin/stats'),
  getPendingSubmissions: () =>
    api.get('/admin/submissions'),
  approveSubmission: (id) =>
    api.post(`/admin/submissions/${id}/approve`),
  rejectSubmission: (id) =>
    api.post(`/admin/submissions/${id}/reject`),
};

export const bookmarkAPI = {
  addBookmark: (id) =>
    api.post(`/bookmarks/${id}`),
  removeBookmark: (id) =>
    api.delete(`/bookmarks/${id}`),
  getBookmarks: () =>
    api.get('/bookmarks'),
  isBookmarked: (id) =>
    api.get(`/bookmarks/${id}/check`),
};

export const storiesAPI = {
  getAll: () =>
    api.get('/stories'),
  getMyStories: () =>
    api.get('/stories/my-stories'),
  getById: (id) =>
    api.get(`/stories/${id}`),
  create: (title) =>
    api.post('/stories', { title }),
  update: (id, title, content) =>
    api.put(`/stories/${id}`, { title, content }),
  delete: (id) =>
    api.delete(`/stories/${id}`),
  addCollaborator: (storyId, userId) =>
    api.post(`/stories/${storyId}/collaborators`, { userId }),
  removeCollaborator: (storyId, userId) =>
    api.delete(`/stories/${storyId}/collaborators/${userId}`),
  linkWord: (storyId, entryId, wordText) =>
    api.post(`/stories/${storyId}/link-word`, { entryId, wordText }),
  unlinkWord: (storyId, entryId) =>
    api.delete(`/stories/${storyId}/link-word/${entryId}`),
};

export default api;
