import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { storiesAPI } from '../api';
import StoryEditor from '../components/StoryEditor';
import CreateEntryModal from '../components/CreateEntryModal';
import './StoryEditPage.css';

function StoryEditPage({ user }) {
  const { id } = useParams();
  const navigate = useNavigate();
  const [story, setStory] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [content, setContent] = useState('');
  const [saving, setSaving] = useState(false);
  const [selectedWord, setSelectedWord] = useState('');
  const [showCreateEntryModal, setShowCreateEntryModal] = useState(false);
  const [chapters, setChapters] = useState([]);
  const [currentChapter, setCurrentChapter] = useState(0);
  const [showChapterMenu, setShowChapterMenu] = useState(false);

  useEffect(() => {
    if (id) {
      fetchStory();
    } else {
      // Creating new story - just set empty content
      setLoading(false);
    }
  }, [id]);

  const fetchStory = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await storiesAPI.getById(id);
      setStory(res.data);
      setContent(res.data.content || '');
      parseChapters(res.data.content || '');
    } catch (err) {
      console.error('Error fetching story:', err);
      setError('Failed to load story');
    } finally {
      setLoading(false);
    }
  };

  const parseChapters = (html) => {
    // Simple chapter parsing - look for h2 headings as chapter markers
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    const h2s = doc.querySelectorAll('h2');
    const chapterList = [];
    h2s.forEach((h2, index) => {
      chapterList.push({
        number: index + 1,
        title: h2.textContent || `Chapter ${index + 1}`,
      });
    });
    setChapters(chapterList.length > 0 ? chapterList : [{ number: 1, title: 'Main' }]);
  };

  const handleSave = async () => {
    if (!id) {
      // New story - should be created from Stories page
      return;
    }

    setSaving(true);
    setError('');
    try {
      const res = await storiesAPI.update(id, story.title, content);
      setStory(res.data);
      // Show success message
      const msg = document.createElement('div');
      msg.className = 'success-message';
      msg.textContent = 'Saved!';
      document.body.appendChild(msg);
      setTimeout(() => msg.remove(), 2000);
    } catch (err) {
      console.error('Error saving story:', err);
      setError('Failed to save story');
    } finally {
      setSaving(false);
    }
  };

  const handleWordSelected = (word) => {
    setSelectedWord(word);
    setShowCreateEntryModal(true);
  };

  const handleEntryCreated = async (entry) => {
    // Link the word to the story
    try {
      await storiesAPI.linkWord(id, entry.id, selectedWord);
      setShowCreateEntryModal(false);
      setSelectedWord('');
    } catch (err) {
      console.error('Error linking word:', err);
    }
  };

  const jumpToChapter = (chapterNumber) => {
    // Find the h2 for this chapter and scroll to it
    const parser = new DOMParser();
    const doc = parser.parseFromString(content, 'text/html');
    const h2s = doc.querySelectorAll('h2');
    if (h2s[chapterNumber - 1]) {
      setCurrentChapter(chapterNumber - 1);
      setShowChapterMenu(false);
      // Scroll in the editor
      setTimeout(() => {
        const editorElement = document.querySelector('.ProseMirror');
        if (editorElement) {
          const h2Element = editorElement.querySelectorAll('h2')[chapterNumber - 1];
          if (h2Element) {
            h2Element.scrollIntoView({ behavior: 'smooth' });
          }
        }
      }, 100);
    }
  };

  if (!user) {
    return (
      <div className="container">
        <div className="story-edit-page">
          <p className="no-auth">Please log in to edit stories.</p>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="container">
        <div className="story-edit-page">
          <p className="loading">Loading story...</p>
        </div>
      </div>
    );
  }

  if (error && !story) {
    return (
      <div className="container">
        <div className="story-edit-page">
          <div className="error">{error}</div>
          <button onClick={() => navigate('/stories')} className="btn-back">
            Back to Stories
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="story-edit-page">
        <div className="story-header">
          <div className="story-title-section">
            <button onClick={() => navigate('/stories')} className="btn-back-arrow" title="Back">
              ← Back
            </button>
            <h1>{story?.title || 'New Story'}</h1>
          </div>

          {chapters.length > 1 && (
            <div className="chapter-menu-container">
              <button 
                onClick={() => setShowChapterMenu(!showChapterMenu)}
                className="btn-chapters"
              >
                📖 Jump to Chapter
              </button>
              {showChapterMenu && (
                <div className="chapter-menu">
                  {chapters.map(ch => (
                    <button
                      key={ch.number}
                      onClick={() => jumpToChapter(ch.number)}
                      className={`chapter-item ${currentChapter === ch.number - 1 ? 'active' : ''}`}
                    >
                      {ch.title}
                    </button>
                  ))}
                </div>
              )}
            </div>
          )}

          <div className="story-actions">
            {error && <div className="error-inline">{error}</div>}
            <button 
              onClick={handleSave}
              disabled={saving}
              className="btn-save"
            >
              {saving ? 'Saving...' : 'Save Story'}
            </button>
          </div>
        </div>

        <div className="story-editor-wrapper">
          <StoryEditor 
            initialContent={content}
            onContentChange={setContent}
            onWordSelected={handleWordSelected}
            linkedWords={story?.linkedWords || []}
          />
        </div>

        <CreateEntryModal 
          isOpen={showCreateEntryModal}
          onClose={() => {
            setShowCreateEntryModal(false);
            setSelectedWord('');
          }}
          onEntryCreated={handleEntryCreated}
          suggestedWord={selectedWord}
        />
      </div>
    </div>
  );
}

export default StoryEditPage;
