import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { storiesAPI } from '../api';
import './Stories.css';

function Stories({ user }) {
  const [stories, setStories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newStoryTitle, setNewStoryTitle] = useState('');
  const [creating, setCreating] = useState(false);

  useEffect(() => {
    if (user) {
      fetchStories();
    }
  }, [user]);

  const fetchStories = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await storiesAPI.getMyStories();
      setStories(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      console.error('Error fetching stories:', err);
      setError('Failed to load stories');
    } finally {
      setLoading(false);
    }
  };

  const handleCreateStory = async (e) => {
    e.preventDefault();
    if (!newStoryTitle.trim()) {
      setError('Story title is required');
      return;
    }

    setCreating(true);
    setError('');
    try {
      const res = await storiesAPI.create(newStoryTitle.trim());
      setStories([res.data, ...stories]);
      setNewStoryTitle('');
      setShowCreateForm(false);
    } catch (err) {
      console.error('Error creating story:', err);
      setError('Failed to create story');
    } finally {
      setCreating(false);
    }
  };

  const handleDeleteStory = async (storyId, storyTitle) => {
    if (!window.confirm(`Delete story "${storyTitle}"? This cannot be undone.`)) {
      return;
    }

    try {
      await storiesAPI.delete(storyId);
      setStories(stories.filter(s => s.id !== storyId));
    } catch (err) {
      console.error('Error deleting story:', err);
      setError('Failed to delete story');
    }
  };

  if (!user) {
    return (
      <div className="container">
        <div className="stories-page">
          <h1>Stories</h1>
          <p className="no-auth">Please log in to create and edit stories.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="stories-page">
        <h1>My Stories</h1>
        <p className="subtitle">Write and share stories using made-up words</p>

        {error && <div className="error">{error}</div>}

        {!showCreateForm ? (
          <button onClick={() => setShowCreateForm(true)} className="btn-new-story">
            + New Story
          </button>
        ) : (
          <form onSubmit={handleCreateStory} className="create-story-form">
            <div className="form-group">
              <label htmlFor="story-title">Story Title</label>
              <input
                id="story-title"
                type="text"
                value={newStoryTitle}
                onChange={(e) => setNewStoryTitle(e.target.value)}
                placeholder="Enter a title for your story..."
                disabled={creating}
                autoFocus
              />
            </div>
            <div className="form-actions">
              <button type="submit" disabled={creating}>
                {creating ? 'Creating...' : 'Create Story'}
              </button>
              <button 
                type="button" 
                onClick={() => setShowCreateForm(false)}
                disabled={creating}
                className="btn-cancel"
              >
                Cancel
              </button>
            </div>
          </form>
        )}

        {loading ? (
          <p className="loading">Loading stories...</p>
        ) : stories.length === 0 ? (
          <div className="empty-state">
            <h3>No stories yet</h3>
            <p>Create your first story to get started!</p>
          </div>
        ) : (
          <div className="stories-list">
            {stories.map(story => (
              <div key={story.id} className="story-card">
                <Link to={`/stories/${story.id}`} className="story-link">
                  <h2>{story.title}</h2>
                  <p className="story-meta">
                    By {story.created_by_username}
                    {story.collaborator_count > 0 && ` • ${story.collaborator_count} collaborator${story.collaborator_count !== 1 ? 's' : ''}`}
                  </p>
                  <p className="story-date">
                    Updated {new Date(story.updated_at).toLocaleDateString()}
                  </p>
                </Link>
                {story.created_by === user.id && (
                  <button 
                    onClick={() => handleDeleteStory(story.id, story.title)}
                    className="btn-delete"
                    title="Delete story"
                  >
                    ×
                  </button>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default Stories;
