import React, { useState, useCallback } from 'react';
import { useEditor, EditorContent } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import Link from '@tiptap/extension-link';
import TextAlign from '@tiptap/extension-text-align';
import Highlight from '@tiptap/extension-highlight';
import Color from '@tiptap/extension-color';
import TaskList from '@tiptap/extension-task-list';
import TaskItem from '@tiptap/extension-task-item';
import FontFamily from '@tiptap/extension-font-family';
import Underline from '@tiptap/extension-underline';
import Subscript from '@tiptap/extension-subscript';
import Superscript from '@tiptap/extension-superscript';
import Image from '@tiptap/extension-image';
import './StoryEditor.css';

export default function StoryEditor({ initialContent = '', onSave, onContentChange, linkedWords = [], onChapterUpdate, onWordSelected }) {
  const [selectedText, setSelectedText] = useState('');
  const [chapters, setChapters] = useState([]);
  const [activeChapter, setActiveChapter] = useState(null);
  const [editingChapterId, setEditingChapterId] = useState(null);
  const [editingChapterName, setEditingChapterName] = useState('');
  const [fontSize, setFontSize] = useState('16px');
  const [fontFamily, setFontFamily] = useState('system');
  const [charCount, setCharCount] = useState(0);

  const editor = useEditor({
    extensions: [
      StarterKit.configure({
        heading: { levels: [1, 2, 3, 4, 5, 6] },
      }),
      Link.configure({ openOnClick: false }),
      TextAlign.configure({ types: ['heading', 'paragraph'] }),
      Highlight.configure({ multicolor: true }),
      Color.configure({
        types: ['textStyle'],
      }),
      FontFamily.configure({
        types: ['textStyle'],
      }),
      Underline,
      Subscript,
      Superscript,
      Image.configure({
        allowBase64: true,
      }),
      TaskList,
      TaskItem.configure({
        nested: true,
      }),
    ],
    content: initialContent,
    onUpdate: ({ editor: ed }) => {
      const html = ed.getHTML();
      const text = ed.getText();
      setCharCount(text.length);
      if (onContentChange) {
        onContentChange(html);
      }
      updateChapters(ed.getHTML());
    },
  });

  const updateChapters = (content) => {
    const parser = new DOMParser();
    const doc = parser.parseFromString(content, 'text/html');
    const h2s = doc.querySelectorAll('h2');
    const newChapters = Array.from(h2s).map((h2, idx) => ({
      id: idx,
      title: h2.textContent || `Chapter ${idx + 1}`,
      level: 2,
    }));
    if (newChapters.length > 0) {
      setChapters(newChapters);
      if (onChapterUpdate) {
        onChapterUpdate(newChapters);
      }
    }
  };

  const handleMouseUp = () => {
    if (!editor) return;

    const { from, to } = editor.state.selection;
    if (from === to) {
      setSelectedText('');
      return;
    }

    const text = editor.state.doc.textBetween(from, to);
    setSelectedText(text.trim());
  };

  const handleAddWord = () => {
    if (selectedText && onWordSelected) {
      onWordSelected(selectedText);
      setSelectedText('');
    }
  };

  const jumpToChapter = (chapterId) => {
    const editorElement = document.querySelector('.ProseMirror');
    if (editorElement) {
      const h2s = editorElement.querySelectorAll('h2');
      if (h2s[chapterId]) {
        h2s[chapterId].scrollIntoView({ behavior: 'smooth' });
        setActiveChapter(chapterId);
      }
    }
  };

  const startEditChapter = (chapterId, currentName) => {
    setEditingChapterId(chapterId);
    setEditingChapterName(currentName);
  };

  const saveChapterName = (chapterId) => {
    if (!editor) return;

    const editorElement = document.querySelector('.ProseMirror');
    if (editorElement) {
      const h2s = editorElement.querySelectorAll('h2');
      if (h2s[chapterId]) {
        h2s[chapterId].textContent = editingChapterName;
        // Update chapters array
        const updatedChapters = chapters.map(ch => 
          ch.id === chapterId ? { ...ch, title: editingChapterName } : ch
        );
        setChapters(updatedChapters);
        if (onChapterUpdate) {
          onChapterUpdate(updatedChapters);
        }
      }
    }
    setEditingChapterId(null);
  };

  const handleImageUpload = useCallback((e) => {
    const file = e.target.files?.[0];
    if (!file || !editor) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const src = event.target?.result;
      editor.chain().focus().setImage({ src }).run();
    };
    reader.readAsDataURL(file);
  }, [editor]);

  const insertTaskList = useCallback(() => {
    if (!editor) return;
    editor.chain().focus().toggleTaskList().run();
  }, [editor]);

  const handleFontSizeChange = useCallback((size) => {
    if (!editor) return;
    setFontSize(size);
    editor.chain().focus().setMark('textStyle', { fontSize: size }).run();
  }, [editor]);

  const handleFontFamilyChange = useCallback((family) => {
    if (!editor) return;
    setFontFamily(family);
    const fontMap = {
      system: 'system-ui, sans-serif',
      serif: 'Georgia, serif',
      mono: 'Courier New, monospace',
      comic: 'Comic Sans MS, cursive',
    };
    editor.chain().focus().setFontFamily(fontMap[family] || family).run();
  }, [editor]);

  return (
    <div className="story-editor-wrapper-full">
      <div className="chapter-sidebar">
        <div className="chapters-header">
          <h3>📖 Chapters</h3>
        </div>
        {chapters.length === 0 ? (
          <p className="no-chapters">Use H2 (Heading 2) to create new chapters</p>
        ) : (
          <div className="chapters-list">
            {chapters.map((ch, idx) => (
              <div 
                key={ch.id} 
                className={`chapter-item ${activeChapter === ch.id ? 'active' : ''}`}
              >
                {editingChapterId === ch.id ? (
                  <div className="chapter-edit-form">
                    <input
                      type="text"
                      value={editingChapterName}
                      onChange={(e) => setEditingChapterName(e.target.value)}
                      autoFocus
                    />
                    <button onClick={() => saveChapterName(ch.id)} className="btn-save-ch">✓</button>
                    <button onClick={() => setEditingChapterId(null)} className="btn-cancel-ch">✕</button>
                  </div>
                ) : (
                  <>
                    <button 
                      onClick={() => jumpToChapter(ch.id)}
                      className="chapter-link"
                    >
                      {idx + 1}. {ch.title}
                    </button>
                    <button 
                      onClick={() => startEditChapter(ch.id, ch.title)}
                      className="btn-edit-ch"
                      title="Rename chapter"
                    >
                      ✏️
                    </button>
                  </>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="story-editor-container">
        <div className="editor-toolbar">
          {selectedText && (
            <div className="selection-toolbar">
              <span>Selected: "{selectedText}"</span>
              <button onClick={handleAddWord} className="btn-add-word">
                ⭐ Add to Wiki
              </button>
            </div>
          )}

          <div className="formatting-toolbar">
            {/* Font Controls Group */}
            <div className="toolbar-group">
              <select 
                value={fontFamily}
                onChange={(e) => handleFontFamilyChange(e.target.value)}
                disabled={!editor}
                title="Font family"
                className="font-select"
              >
                <option value="system">System Font</option>
                <option value="serif">Serif (Georgia)</option>
                <option value="mono">Monospace</option>
                <option value="comic">Comic Sans</option>
              </select>
              <select
                value={fontSize}
                onChange={(e) => handleFontSizeChange(e.target.value)}
                disabled={!editor}
                title="Font size"
                className="font-size-select"
              >
                <option value="12px">12px</option>
                <option value="14px">14px</option>
                <option value="16px">16px</option>
                <option value="18px">18px</option>
                <option value="20px">20px</option>
                <option value="24px">24px</option>
                <option value="28px">28px</option>
              </select>
            </div>

            <div className="toolbar-divider"></div>

            {/* Text Style Group */}
            <div className="toolbar-group">
              <button
                onClick={() => editor?.chain().focus().toggleBold().run()}
                disabled={!editor}
                className={editor?.isActive('bold') ? 'active' : ''}
                title="Bold (Ctrl+B)"
              >
                <strong>B</strong>
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleItalic().run()}
                disabled={!editor}
                className={editor?.isActive('italic') ? 'active' : ''}
                title="Italic (Ctrl+I)"
              >
                <em>I</em>
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleUnderline().run()}
                disabled={!editor}
                className={editor?.isActive('underline') ? 'active' : ''}
                title="Underline (Ctrl+U)"
              >
                <u>U</u>
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleStrike().run()}
                disabled={!editor}
                className={editor?.isActive('strike') ? 'active' : ''}
                title="Strikethrough"
              >
                <s>S</s>
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleSubscript().run()}
                disabled={!editor}
                className={editor?.isActive('subscript') ? 'active' : ''}
                title="Subscript"
              >
                X<sub>2</sub>
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleSuperscript().run()}
                disabled={!editor}
                className={editor?.isActive('superscript') ? 'active' : ''}
                title="Superscript"
              >
                X<sup>2</sup>
              </button>
            </div>

            <div className="toolbar-divider"></div>

            {/* Heading Group */}
            <div className="toolbar-group">
              <button
                onClick={() => editor?.chain().focus().toggleHeading({ level: 2 }).run()}
                disabled={!editor}
                className={editor?.isActive('heading', { level: 2 }) ? 'active' : ''}
                title="Heading 2 (Chapter)"
              >
                H2
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleHeading({ level: 3 }).run()}
                disabled={!editor}
                className={editor?.isActive('heading', { level: 3 }) ? 'active' : ''}
                title="Heading 3"
              >
                H3
              </button>
              <button
                onClick={() => editor?.chain().focus().setParagraph().run()}
                disabled={!editor}
                className={editor?.isActive('paragraph') ? 'active' : ''}
                title="Paragraph"
              >
                ¶
              </button>
            </div>

            <div className="toolbar-divider"></div>

            {/* Alignment Group */}
            <div className="toolbar-group">
              <button
                onClick={() => editor?.chain().focus().setTextAlign('left').run()}
                disabled={!editor}
                className={editor?.isActive({ textAlign: 'left' }) ? 'active' : ''}
                title="Align left"
              >
                ⬅
              </button>
              <button
                onClick={() => editor?.chain().focus().setTextAlign('center').run()}
                disabled={!editor}
                className={editor?.isActive({ textAlign: 'center' }) ? 'active' : ''}
                title="Align center"
              >
                ⬍
              </button>
              <button
                onClick={() => editor?.chain().focus().setTextAlign('right').run()}
                disabled={!editor}
                className={editor?.isActive({ textAlign: 'right' }) ? 'active' : ''}
                title="Align right"
              >
                ➡
              </button>
            </div>

            <div className="toolbar-divider"></div>

            {/* List Group */}
            <div className="toolbar-group">
              <button
                onClick={() => editor?.chain().focus().toggleBulletList().run()}
                disabled={!editor}
                className={editor?.isActive('bulletList') ? 'active' : ''}
                title="Bullet list"
              >
                ⊙ List
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleOrderedList().run()}
                disabled={!editor}
                className={editor?.isActive('orderedList') ? 'active' : ''}
                title="Numbered list"
              >
                1. List
              </button>
              <button
                onClick={insertTaskList}
                disabled={!editor}
                className={editor?.isActive('taskList') ? 'active' : ''}
                title="Task list"
              >
                ☑ Task
              </button>
            </div>

            <div className="toolbar-divider"></div>

            {/* Colors & Highlight Group */}
            <div className="toolbar-group">
              <input
                type="color"
                onInput={(event) =>
                  editor?.chain().focus().setColor(event.currentTarget.value).run()
                }
                value={editor?.getAttributes('textStyle').color || '#000000'}
                disabled={!editor}
                title="Text color"
                className="color-picker"
              />
              <select
                onChange={(e) => {
                  if (e.target.value === 'none') {
                    editor?.chain().focus().clearHighlight().run();
                  } else {
                    editor?.chain().focus().setHighlight({ color: e.target.value }).run();
                  }
                }}
                disabled={!editor}
                title="Highlight color"
                className="highlight-select"
              >
                <option value="none">No highlight</option>
                <option value="#fff3bf">Yellow</option>
                <option value="#ffe7e6">Red</option>
                <option value="#d3f261">Green</option>
                <option value="#87d4ff">Blue</option>
              </select>
            </div>

            <div className="toolbar-divider"></div>

            {/* Table, Image & Blocks Group */}
            <div className="toolbar-group">
              <label className="image-upload-label" title="Insert image">
                🖼 Image
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleImageUpload}
                  disabled={!editor}
                  style={{ display: 'none' }}
                />
              </label>
              <button
                onClick={() => editor?.chain().focus().toggleBlockquote().run()}
                disabled={!editor}
                className={editor?.isActive('blockquote') ? 'active' : ''}
                title="Blockquote"
              >
                ❝ Quote
              </button>
              <button
                onClick={() => editor?.chain().focus().toggleCodeBlock().run()}
                disabled={!editor}
                className={editor?.isActive('codeBlock') ? 'active' : ''}
                title="Code block"
              >
                &lt;&gt;
              </button>
              <button
                onClick={() => editor?.chain().focus().setHorizontalRule().run()}
                disabled={!editor}
                title="Horizontal line"
              >
                ─
              </button>
            </div>

            <div className="toolbar-divider"></div>

            {/* Undo/Redo */}
            <div className="toolbar-group">
              <button
                onClick={() => editor?.chain().focus().undo().run()}
                disabled={!editor?.can().undo()}
                title="Undo"
              >
                ↶ Undo
              </button>
              <button
                onClick={() => editor?.chain().focus().redo().run()}
                disabled={!editor?.can().redo()}
                title="Redo"
              >
                ↷ Redo
              </button>
            </div>

            {/* Character Count */}
            <div className="char-count">
              📝 {charCount} characters
            </div>
          </div>
        </div>

        <div 
          className="editor-content-area" 
          onMouseUp={handleMouseUp}
        >
          <EditorContent editor={editor} />
        </div>
      </div>
    </div>
  );
}
