import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { bookmarkAPI } from '../api';
import './Bookmarks.css';

function Bookmarks({ user }) {
  const navigate = useNavigate();
  const [bookmarks, setBookmarks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  useEffect(() => {
    if (!user) {
      navigate('/');
      return;
    }
    fetchBookmarks();
  }, [user, navigate]);

  const fetchBookmarks = async () => {
    setLoading(true);
    setError('');
    try {
      const response = await bookmarkAPI.getBookmarks();
      setBookmarks(response.data);
    } catch (err) {
      console.error('Error fetching bookmarks:', err);
      setError('Failed to load bookmarks');
    } finally {
      setLoading(false);
    }
  };

  const handleRemoveBookmark = async (entryId, wordName) => {
    try {
      await bookmarkAPI.removeBookmark(entryId);
      setBookmarks(bookmarks.filter(b => b.id !== entryId));
      setMessage(`Removed "${wordName}" from bookmarks`);
      setTimeout(() => setMessage(''), 3000);
    } catch (err) {
      console.error('Error removing bookmark:', err);
      setError('Failed to remove bookmark');
    }
  };

  if (!user) {
    return <div className="bookmarks-page">Please log in to view bookmarks</div>;
  }

  return (
    <div className="bookmarks-page">
      <div className="bookmarks-container">
        <Link to="/" className="back-link">← Back</Link>
        
        <h1>My Bookmarks</h1>

        {error && <div className="error-message">{error}</div>}
        {message && <div className="success-message">{message}</div>}

        {loading ? (
          <div className="loading">Loading bookmarks...</div>
        ) : bookmarks.length > 0 ? (
          <div className="bookmarks-list">
            {bookmarks.map((entry) => (
              <div key={entry.id} className="bookmark-item">
                <div className="bookmark-content">
                  <Link to={`/word/${entry.word}`} className="bookmark-word">
                    <h3>{entry.word}</h3>
                  </Link>
                  {entry.part_of_speech && (
                    <span className="part-of-speech">{entry.part_of_speech}</span>
                  )}
                  {entry.definition && (
                    <p className="bookmark-definition">
                      {entry.definition.substring(0, 150)}
                      {entry.definition.length > 150 ? '...' : ''}
                    </p>
                  )}
                  <div className="bookmark-meta">
                    {entry.views && <span className="views-badge">{entry.views} views</span>}
                    {entry.categories && <span className="categories-badge">{entry.categories}</span>}
                  </div>
                </div>
                <button
                  className="remove-btn"
                  onClick={() => handleRemoveBookmark(entry.id, entry.word)}
                  title="Remove bookmark"
                  aria-label={`Remove ${entry.word} from bookmarks`}
                >
                  <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"></path>
                  </svg>
                </button>
              </div>
            ))}
          </div>
        ) : (
          <div className="no-bookmarks">
            <p>No bookmarks yet. Start bookmarking words to save them here!</p>
            <Link to="/" className="btn-primary">Browse Words</Link>
          </div>
        )}
      </div>
    </div>
  );
}

export default Bookmarks;
